INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027e4de3c98b0941765bed', '在花园酒店住了一晚，广州老牌五星酒店，坐落在有点异域风情的建设六马路旁，总体来讲体验还不错。
环境：客房隔音不错，楼下施工也没有什么声音。一楼有很漂亮的后花园，吃完早餐去逛逛很舒服。四楼的博物馆也可以逛逛蛮有趣的。但是空中花园和泳池在装修，有点可惜。
设施：总体比较老旧，不过能看出来细心维护，卫生也做的不错。床也睡的挺舒服的。
早餐：挺丰富的，在瀑布餐厅，各国菜式都有，看着瀑布和花园吃早餐有种在度假的感觉，很喜欢～
服务：服务一般，需要提升。checkin办理时间巨长，且全程没有一些提示，会让客人干等着。早餐指引入座也有同样的问题。总的来说就是“我什么都做了但我毫无感情”。最后押金退还失败也没有人来通知，主动打电话三次才办妥，这里效率有点低。作为五星标准，我觉得服务应该要跟上。', '["https://dimg04.c-ctrip.com/images/0236k12000c27apgy3C15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000c27buuaB46B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000c2713raA770_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000c27585e763E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-09-12', '红棉大床套房', '套房', '情侣出游', 343, 1, 15, 9, '["退房/入住效率","安静程度","餐饮设施"]'::jsonb, '退房/入住效率', '安静程度', '餐饮设施'),
('68027e4de3c98b0941765bee', '环境：非常棒，是我目前住过的酒店内部环境最好的了

设施：原来订的红棉大床房，入住的时候说给做了小小的升级，给了个同样面积但是近几年装修的房间。房间设施总体还不错，不过以这个价位来说算不上惊艳。电视不错，三星的，尺寸也够大。虽然不能使用手机投屏，但电视节目很多，HBO也能直接放，还有一些4K的频道。酒店还配了针线包，而且这针线包看着还不错。酒店的拖鞋很舒服，配了大小两个尺码，打电话给前台还会给一双小孩子的拖鞋。就是拖鞋的防滑不太好，洗脸盆附近地方弄了水之后，我在洗漱的时候还滑了一跤，脚趾撞到台下的洗衣篮了，现在都还有点疼呢！在吐槽下酒店配了浴缸和浴盐，一开始我没看到浴盐打电话问前台要浴盐，前台居然说酒店没有浴盐，这业务也太不熟悉了吧！然后还问了有没有一次性浴缸套的也说没有，不知道真没有呢还是假没有呢？还有一个比较失望的就是坐便器了，19年重新装修的居然没有配智能马桶，而且这个普通的??也不好，厕纸扔在马桶前端的位置的话居然会冲不下去，因为冲水的时候前端这个位置冲不到水！再来说点好的，有咖啡机有胶囊，茶包配的TWG。说完房间，说下酒店公区的部份，那是真的豪华，这才对得起这么贵的房价。酒店一进门先是有个小的大堂，左右两边墙上分别有百骏图和百美图。然后再进去才是酒店真正的大堂，那叫一个金碧辉煌，前台身后的那幅红楼梦据说使用金箔贴的，有钱是真的任性。对着前台在我们的右手边是瀑布餐厅，我们的早餐就是在这里吃的，环境很棒，抬头就能看到外面的人造瀑布。早餐种类不算多，不过味道都还不错，水果也比较新鲜，酸奶稍微差点，只有调味的酸奶。咖啡机做的??也挺好的。外面瀑布连着的是酒店的一个大花园，没大太阳的时候去逛逛还是挺惬意的，逛累了就能直接回楼上休息。酒店酒店4楼还有一个酒店博物馆，面积还挺大，内容挺多，不是随便糊弄的。要参观的话直接过去在门口手机扫码实名预约一下就可以了。最后说一下酒店的餐厅，我们现在大众点评上看了下几个餐厅的人均消费，一看吓死个人，还有我们有送的消费券，最后选了个其中比较便宜的荔湾亭，想着两个人500元怎么也应该能吃饱吧。很遗憾，最后吃完花了500多后，我是饿着肚子出来的??

服务：服务中规中矩。', '["https://dimg04.c-ctrip.com/images/0205p12000c2pnl5r74CD_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232c12000c2pcyg1E4AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000c2p8qv59E6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000c2p3dmc14CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000c2p4wbl2E59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-09-05', '红棉大床套房', '套房', '家庭亲子', 915, 0, 6, 9, '["房间设施","公共设施","餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施'),
('68027e4de3c98b0941765bef', '市中心老牌五星级酒店，交通方便，酒店房间设施还比较新，干净，舒服。服务则有待加强，有点令人失望。
1. 入住和退房光排队各要15分钟，每个人办入住时间太长。退房时还比人插队，前台小姐姐没注意客人是否有排队。
2. 酒店早餐种类和服务对比同集团的南沙花园差太远了，吐槽一下负责蛋类制作的，估计是不粘锅使用太长时间了，不粘涂层都没有了，煎出来的鸡蛋基本是胡边的。Onmelet的制作技巧有待加强，早餐很多外国客人会点这个。', '["https://dimg04.c-ctrip.com/images/0235u12000c26yv8l5E96_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000c26phtz85AE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-09-03', '花园大床房', '大床房', '商务出差', 209, 1, 14, 8, '["退房/入住效率","餐饮设施","房间设施"]'::jsonb, '退房/入住效率', '餐饮设施', '房间设施'),
('68027e4de3c98b0941765bf0', '老酒店位置方便', '["https://dimg04.c-ctrip.com/images/0230412000d7w8s3x0B2B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-16', '红棉大床套房', '套房', '家庭亲子', 7, 0, 10, 4, '["交通便利性"]'::jsonb, '交通便利性', NULL, NULL),
('68027e4de3c98b0941765bf1', '干净整洁，位置不错', '["https://dimg04.c-ctrip.com/images/0231k12000diz4r8p4ACE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-28', '花园大床房', '大床房', '家庭亲子', 9, 0, 11, 4, '["卫生状况","交通便利性"]'::jsonb, '卫生状况', '交通便利性', NULL),
('68027e58e3c98b0941765bf2', '酒店服务非常好，感谢小钟为我们升级房间。', '["https://dimg04.c-ctrip.com/images/0233312000d0jka8g0601_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000d0jka8l0599_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000d0jjwhp70EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-23', '花园大床房', '大床房', '家庭亲子', 20, 0, 2, 5, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027e58e3c98b0941765bf3', '虽然是老牌五星，但非常适合', '["https://dimg04.c-ctrip.com/images/0232b12000d307qvtCBF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-30', '城央绿意大床房', '大床房', '其他', 13, 0, 11, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e58e3c98b0941765bf4', '这次又来入住广州花园酒店，因为离家近????小朋友们的staycation了～不知道为什么前台办理入住还是那么慢??房间升级了红棉客房，但是看到房间的刷牙杯垫发黄了，而且洗漱的时候很容易水就流出去杯子的区域??叫客房服务送东西，送第三次的时候，服务员很直接地说：你们还有要什么？要想清楚哈，不要等下又要叫??要不酒店也配几个送东西的机器人？这样不用劳烦服务员。
和之前疫情期间比起来，行政酒廊的餐饮丰富了很多，基本上早餐和晚餐在酒廊解决了，如果晚上能加两个热菜就完美了～
这次酒廊的小姐姐们都很温柔nice，Carrie、Katherine、cherry、Yana她们都很尽职尽责，特别是Carrie，对小孩子特别温柔，会及时帮忙??????
其他：希望酒店能加一些适合孩子们玩的游乐设施', '["https://dimg04.c-ctrip.com/images/0236n12000c26b8p825FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000c265y2y770C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000c26c0ubB2E0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '花园大床房', '大床房', '家庭亲子', 344, 0, 1, 8, '["客房服务","房间设施","餐饮设施"]'::jsonb, '客房服务', '房间设施', '餐饮设施'),
('68027e58e3c98b0941765bf5', '九零年代就来花园酒店住过，这次来广州带着对花园的情节又住了3晚上，酒店界的标杆非花园莫属，一如既往地好，还会再来', '["https://dimg04.c-ctrip.com/images/0230x12000civavllE92D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000ciuzz7q7671_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000civ5lkx73BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000civ5freF3E1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-06', '花园大床房', '大床房', '独自旅行', 56, 0, 8, 6, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e58e3c98b0941765bf6', '老牌国际五星酒店，服务没话说。酒店环境也很好。有自己的绿化小公园很漂亮，还有瀑布和酒店博物馆', '["https://dimg04.c-ctrip.com/images/0233e12000cq046x6BC85_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000cq00uddFE65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000cq0avir9AAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000cq00xghAA71_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-12', '花园双床房', '双床房', '朋友出游', 46, 0, 21, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027e58e3c98b0941765bf7', '酒店各种服务都很到位。几家餐厅的菜品质量都非常不错。推荐酒店导览。', '["https://dimg04.c-ctrip.com/images/0231z12000crv1ojf0907_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-21', '红棉大床套房', '套房', '家庭亲子', 33, 0, 8, 5, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027e58e3c98b0941765bf8', '老酒店，啊不错', '["https://dimg04.c-ctrip.com/images/0230512000d6tbd6m6E1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000d6sq8b0648C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-12', '花园大床房', '大床房', '家庭亲子', 7, 0, 17, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e58e3c98b0941765bf9', '本来的订的双床房到了前台Billy直接给我升级到了红棉套房，前台的服务真的非常好！整个酒店一进门就感受到了文化底蕴，真的超级漂亮。大堂每个地方都很好拍，有很多外国友人选择这家酒店，瀑布餐厅也是一大亮点，带小孩过来挺方便的。', '["https://dimg04.c-ctrip.com/images/0231u12000c1peaw69B26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000c1pe8aq693A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000c1pf94r1BC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000c1ph83q2603_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000c1pj2u8AB85_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-01', '花园双床房', '双床房', '家庭亲子', 111, 0, 2, 8, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027e58e3c98b0941765bfa', '终于有机会打卡广州老牌酒店花园酒店，酒店工作人员热情洋溢、年轻活力，感受到无微不至的关怀，特别感谢Savanna和Ariel的亲切服务。酒店翻新后硬件提升更好，客房硬件用料扎实。公区富丽堂皇，花园风景如画，博物馆增长见识，颇有都市休闲感觉。让人流连忘返。酒廊早餐有单点，下午茶进步空间大，hh餐食丰富可吃饱，希望以后提升行政酒廊的硬件水平，增加如独立行政酒廊场所，酒廊ci、co服务等。', '["https://dimg04.c-ctrip.com/images/0234o12000ccdm79jEBC5_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233512000ccdm29mB3B9_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236e12000ccdm458E8B8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230k12000ccdmlcbFE3E_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2023-10-06', '花园大床房', '大床房', '独自旅行', 193, 0, 13, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027e58e3c98b0941765bfb', '想给这家酒店写大大的好评!太棒了~这个好评我必须要写
来这家酒店住过了两晚了~三天都觉得身心愉悦都还是那么的棒下次还要来!!!
环境真的超绝!
很适合假期去度假住一天会嫌少的，低调的掩映在车水马龙的城市中央
仿佛一处低调的世外桃源般
服务很棒
前台小姐姐、小哥、扫地的阿姨都好热情啊~
有送入住欢迎下午茶办理入住速度也很快!
酒店设施齐全
有游泳池、健身房园区内还有网红瀑布可以打卡
草坪也不错，百拍照很出片
超级多米其林餐厅，罗氏虾煲超nice!', '["https://dimg04.c-ctrip.com/images/0234112000c4d1wvx6E57_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000c4dax3sD827_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000c4d6cze39F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '红棉大床套房', '套房', '家庭亲子', 224, 0, 12, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027e63e3c98b0941765bfc', '亲爱的花园酒店客服人员你们好，我们非常感谢您的支持与帮助。我们在酒店度过了非常愉快的三天，您让我们享用了很多美食，让我们了解到了花园酒店的历史与现在。再次感谢您的照顾，希望将来还能与你们相遇！——来自二年级的小崔同学口述评语（妈妈帮忙记录）
由衷感谢所有工作人员（行李服务、大堂迎宾、大堂经理、客房服务、30层自助旋转餐厅、工程维护等等）的热忱和美好善意，我们都记下了。期待再次重逢！', '["https://dimg04.c-ctrip.com/images/0235812000cc0y0rw94C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000cc10hu6653B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000cc0w50fD704_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000cc10hu82DB5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000cc0s9tf3EE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000cc0zjclCA6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000cc0witd0C47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000cc10g43A91C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000cc0vqmkB67E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '红棉双床套房', '套房', '家庭亲子', 192, 1, 11, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027e63e3c98b0941765bfd', '免费升级套房，非常宽敞舒适。周围吃饭购物也很便利，四楼还有酒店博物馆，非常用心了。而且步行两百多米就是地铁站，马路对面就是商场，很适合带娃citywalk', '["https://dimg04.c-ctrip.com/images/0235t12000cbmo67z3A67_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 77, 0, 6, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027e63e3c98b0941765bfe', '酒店本身就像一座小花园，瀑布，小桥，金鱼，红花真是风景优美。办理入住时对着红楼梦的壁画真是赏心悦目，酒店的服务超级好，进了大堂就不用管行李了，直接送入房间。因为生日还送了甜品和生日蛋糕，哈哈…', '["https://dimg04.c-ctrip.com/images/0231k12000c54djz0F405_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000c54l84964A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000c548zloEAFE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000c54oy99A52B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-15', '红棉大床套房', '套房', '家庭亲子', 96, 0, 4, 8, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027e63e3c98b0941765bff', '出差来广州，赶在入住时间比较晚了，用了自己在携程大促上囤的券小试一下，前台帮忙升级到了粤韵双床房，在前台稍微等了一下，但抵达房间时发现已经开好了夜床服务，点个赞。整体一定要给五星好评！下次还会来！??????????退房服务也超级Nice！

整体上粤韵套房的性价比超级高，各方面比较新，为了照顾日本旅客吧，双床之间还会有升降拉帘，这种小细节一般只有在日本才能感受到。但是双床房没有浴缸，以及办公位电源位置插不进Mac的充电器

床品对于我来讲非常干爽舒适了，前段时间在香港金钟JW万豪都觉得没有这么干爽舒适，干爽和舒适缺一不可，花园酒店做到了。

酒店餐饮：早餐就有惊艳到了，早餐我吃的2楼荔湾亭，完爆其他酒店，萝卜糕芋头糕牛肉粥等等等是外面各种大酒楼点心店吃不到的香气，幸福到会瞪大眼睛感叹的那种！另外一家是活动房券本身包含了500消费额，用在了桃园馆1人套餐，除了略贵没别的毛病，口感和卖相上匠心独运着实吃出了前中后调。另外最后一道甜品，值得单独说说！近期拔草的所有上海新晋网红店我都提不起兴趣，觉得就那样吧，但是！桃园馆套餐里配的甜品让我觉得我好像还是喜欢吃甜品的！

美中不足：抵达时未见迎宾门童、白天阳光照进房间发现卫生间门上玻璃擦拭不干净、卫生间和卧室之间的拉门上也擦拭不干净，不符合花园酒店的卫生定位。

但是花园酒店的粤韵套房依然很不错，下次值得再来～', '["https://dimg04.c-ctrip.com/images/0236c12000c28x1fkF107_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000c28qqka4222_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000c28uisqF2D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000c28x5c9F401_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000c28w8aw052F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000c28wja3D26D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000c28ugze47AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-03', '红棉双床套房', '套房', '商务出差', 585, 0, 1, 9, '["整体满意度","性价比","卫生状况"]'::jsonb, '整体满意度', '性价比', '卫生状况'),
('68027e63e3c98b0941765c00', '品质非常的perfect,服务态度很好，设施优质，环境优美，地段便利，100米内就是地铁站，而且酒店内的美食非要的地道，特别是红棉房，小孩很喜欢', '["https://dimg04.c-ctrip.com/images/0236r12000cctlsfcEBA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000cctk4la07D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000cctlch5B6C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000cctp2qbB6F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000cctk4tbE562_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉双床套房', '套房', '家庭亲子', 72, 0, 25, 7, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027e63e3c98b0941765c01', '新年初一入住一家三口出行广州，选择了花园酒店。前台Rebecca Zhong非常的热情和耐心。酒店的服务非常好??还赠送了一盆欢迎水果。大床房设计比较开放，对亲子出行需要慎重选择房型。房间台盆下水稍微有点不畅。', '["https://dimg04.c-ctrip.com/images/0237012000d77abzd11CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000d776wxwCDDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000d77bff3E545_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-14', '花园大床房', '大床房', '家庭亲子', 105, 0, 5, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027e63e3c98b0941765c02', '房间很舒适，住得非常开心。前台小姐姐，总机小华，服务员LiLi，保洁阿姨，服务都非常周到细致。下次再来。', '["https://dimg04.c-ctrip.com/images/0234k12000exawcznDA54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000exawczr1D56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000exaw2w601C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-28', '花园大床房', '大床房', '商务出差', 52, 0, 3, 6, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027e63e3c98b0941765c03', '订了双床房 前台办理入住时加了点钱升级到了比原先大一倍的粤韵套房，太划算了，前台小姐姐与酒店的服务人员的服务态度都很好，入住后还送了一套宝格丽洗护用品+蛋糕拼盘??。酒店文化集聚了中国的古典文化特色，后花园也很漂亮，用完餐可以在里面逛逛，酒店的自助餐一流，这次过生日一家三口特意赶过来庆祝了一番，以后还会经常光顾的～', '["https://dimg04.c-ctrip.com/images/0232c12000c198ic6D997_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000c198ic8FE5C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000c19j0l182A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000c19c3mr5ABC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000c19jzzi74EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000c19ilb0EE9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000c19igv90F61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000c19k5q2E586_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-30', '花园双床房', '双床房', '家庭亲子', 158, 0, 1, 9, '["性价比","前台服务","餐饮设施"]'::jsonb, '性价比', '前台服务', '餐饮设施'),
('68027e63e3c98b0941765c04', '真不知道网上为啥有些帖子说酒店不好？带娃在长隆住了两天，因最后一天长隆续房太贵，就定了花园一天，花园酒店升级了到了红棉，进房间后太惊喜，有客厅卫生条件非常好，连拖鞋的质感也超好，服务员阿姨态度非常好，酒店还免费加了床！这个性价比打败我住过所有的酒店。
关键酒店很有历史，国际、大牌、红棉房间设施也很新，隔音效果也不错，外面施工也不吵！周围非常方便，应有尽有！简直挑不出一出毛病来！真的印象太好了！对这次旅行来说真的是点睛之笔！', '["https://dimg04.c-ctrip.com/images/0203d12000c0pbhhf709F_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233312000c0oudqg8BF6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000c0oubyf8EE8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-28', '花园双床房', '双床房', '家庭亲子', 213, 0, 1, 9, '["整体满意度","性价比","房间设施"]'::jsonb, '整体满意度', '性价比', '房间设施'),
('68027e63e3c98b0941765c05', '冲着瀑布订的酒店，但一进酒店就最资深的豪华酒店之一的感觉震撼了，酒店位置和设施都很棒，一点也没老旧的感觉，去的那天正好是酒店多少周年活动，入住送了小饼干和鲜花。从窗户望去的感觉我感觉是值回一半房价的，房间设施也都挺不错的，配的的巴马的矿泉水，就是房间稍显局促，但还OK。孩子特别喜欢这个酒店，就有多住了一晚。交通很方便，门口就是地铁约车都很方便。就是希望服务能再亲民一些就更好了。', '["https://dimg04.c-ctrip.com/images/0233412000c0tv9sp4CD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000c0tw3r22572_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-08-28', '花园双床房', '双床房', '家庭亲子', 190, 0, 10, 8, '["景观/朝向","交通便利性","房间设施"]'::jsonb, '景观/朝向', '交通便利性', '房间设施'),
('68027e6fe3c98b0941765c06', '非常满意的一次体验。前台免费延迟到4点退房，酒店环境设施也一流，服务态度无可挑剔。
入职当天正值中秋，送了小朋友玩具和一盒月饼，关键是月饼的味道非常好！', '["https://dimg04.c-ctrip.com/images/0234x12000cb24v8z482F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000cb1z1ri74F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cb239iz86E3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '红棉大床套房', '套房', '家庭亲子', 76, 0, 1, 8, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027e6fe3c98b0941765c07', '过年气氛很好', '["https://dimg04.c-ctrip.com/images/0231e12000dbetn960E5F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-29', '花园双床房', '双床房', '家庭亲子', 6, 0, 12, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e6fe3c98b0941765c08', '房间很大但显得陈旧了些，必须出新装修的。地段很不错，地铁站就在宾馆门口。', '["https://dimg04.c-ctrip.com/images/0234d12000cplov6kFD62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000cplp5r7DE8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000cpltpwgFBB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000cplj9uj7D51_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000cplssrgFB8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-12-10', '红棉双床套房', '套房', '朋友出游', 36, 0, 32, 6, '["房间设施","交通便利性"]'::jsonb, '房间设施', '交通便利性', NULL),
('68027e6fe3c98b0941765c09', '环境舒适，服务周到。', '["https://dimg04.c-ctrip.com/images/0231z12000d3l696r7EA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-01', '花园双床房', '双床房', '家庭亲子', 10, 0, 12, 3, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027e6fe3c98b0941765c0a', '【位置与环境】占据越秀核心地段，正门外就是地铁淘金站，周边五百米内有几个商场，购物餐饮相当方便。酒店内的几家米其林推荐餐厅比较热门，可能需要预约或等位较长时间。

【设施与服务】老牌五星级酒店，公共空间宽敞大气，花园也算一大特色。但房间布局和设施难免有些陈旧感，优缺点都比较明显。服务没问题，从前台到客房都很亲切负责，中英文服务都很优秀。', '["https://dimg04.c-ctrip.com/images/0236t12000c0r90rvAC43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000c0r9flg1511_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-28', '城央绿意双床房', '双床房', '家庭亲子', 169, 0, 64, 8, '["交通便利性","周边配套","公共设施"]'::jsonb, '交通便利性', '周边配套', '公共设施'),
('68027e6fe3c98b0941765c0b', '酒店里面很漂亮', '["https://dimg04.c-ctrip.com/images/0231512000d5ybscq63D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000d5ykndhA2BF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-09', '花园双床房', '双床房', '家庭亲子', 7, 0, 12, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e6fe3c98b0941765c0c', '红棉大床房套餐非常物超所值，除了国庆期间不能预定。特意去了酒店的桃园馆，菜品果然名不虚传，可用套餐中的500元消费券。因为前两晚所订房型跟最后这日套餐不同，入住时酒店大堂Viria特意帮忙升级了房间，避免换房之苦，帮这次出行节省了不少麻烦，特此感谢。
酒店4楼的博物院值得一去，没想到关于古今酒店业发展历史及未来趋势干货满满，即使在酒店晚一整天也不会感觉枯燥。', '["https://dimg04.c-ctrip.com/images/0236x12000ccyabp99353_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000ccyay1jE05B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000ccy9ybw4EA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000ccy9i1gD0C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000ccy9infA306_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '红棉大床套房', '套房', '朋友出游', 180, 0, 6, 9, '["性价比","餐饮设施","前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务'),
('68027e6fe3c98b0941765c0d', '服务很好，房间也舒适', '["https://dimg04.c-ctrip.com/images/0235512000d6wwyf75F0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '红棉大床套房', '套房', '家庭亲子', 10, 0, 4, 4, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027e6fe3c98b0941765c0e', '老牌酒店，值得入住。', '["https://dimg04.c-ctrip.com/images/0236212000d480zs18570_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000d48ctdf03E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000d488737D218_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000d486d2m59D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000d48h501677F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-03', '花园双床房', '双床房', '家庭亲子', 10, 0, 10, 3, '["整体满意度","性价比"]'::jsonb, '整体满意度', '性价比', NULL),
('68027e6fe3c98b0941765c0f', '收到携程的点评邀请，那就来评评吧，吐槽一下这次入住遇到的小小不愉快。这家酒店之前住过，因为是出差，匆匆来去对服务没啥特别感觉，但环境还是不错的，虽然现在好酒店选择不少，但花园酒店在广州土族同学的心目中一直是高档酒店的存在；个人喜欢现代风格的，所以虽然红棉房间大一些，这次还是订了重新装修后的花园大床房。去的当天飞机长时间延误，起飞时间不确定，候机的时候特意给酒店打电话告知晚上会晚到请她们保留房间（其实房间本身也是不可退的），并且请她帮忙换一下双床房，工作人员也表示已帮忙备注没有问题。我晚上8点到酒店时又累又饿，也不想多说话，和前台提到下午电话请她们换双床房，并问有没有高一些的房间，前台开始了长时间啪啦啪啦敲键盘，过了十多分钟也没好，中间问了我是哪个平台定的房间。后来告诉我没有高楼层的房间，可以给我景观最好的对着瀑布的8楼房间，我拒绝了，这个瀑布很吵影响休息，就问可以升级吗？“有红棉套房”，我说那算了还是给我原来预定的房间吧，有再高一点楼层吗？“最高就是9楼”，我问“今天就没有再高一点房间了？”，回复“今天太晚了（8点多是太晚？）”，我说这和今天太晚有什么关系，有就是有没有就是没有，又是长时间的沉默和敲击键盘，中间前台问了边上的小姑娘，人家不耐烦回复“刚才不是说了没有双床房吗？”，后来前台说“要不今天就住低楼层明天帮你换”，这时候快20分钟过去了，我也有点不高兴，精力也有点恢复了，我说我订的房型本来就是写的18-21楼，携程上这个双床房也可以预定，下午还特意打电话过来说了房间的事，为啥现在没有房间呢（有点不相信这么大体量的酒店还能住满）？请领导过来我问一下，更让人气愤的是边上小姑娘说是领导，就和我们隔了一米的距离一直闲在那，中间没人找她办过入住，前面听了20分钟这边发生的事情，居然能做到一直没反应，始终没主动站出来处理一下，好歹也是家高级酒店，这种服务意识令人失望，小姑娘过来看了电脑没几秒，就说其实给我预留了20楼的双床房前面没看到。无语，我又累又饿白白在前台站20分钟发了一顿火才拿到我预定房间的门卡？也不知道前面迟迟不愿给我预定的房间是出于什么考虑？另外，酒店楼下马路在修路，从早到晚都是机器马达声，喜欢安静的建议绕路这家酒店。', '["https://dimg04.c-ctrip.com/images/0231112000c0ebhen6C01_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000c0eaj5e8EDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000c0e7c941C8A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000c0ecsxp10DA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-08-26', '花园大床房', '大床房', '商务出差', 928, 0, 13, 9, '["前台服务","退房/入住效率","安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度'),
('68027e7de3c98b0941765c10', '名不虚传的美食酒店，里面有四五家餐厅，食物精致美味。打卡了荔湾庭和瀑布餐厅。套餐非常划算，有500元抵用券可以在餐厅抵用。会员赠送了行政酒廊早晚餐和下午茶。酒店里充满具有岭南特色的装饰，红龙梦金箔壁画、木雕藻井、木雕家具等等，还有博物馆和后花园可以餐馆。住宿设施上，红棉房床品舒适度极高，设施齐备。唯一不足的是老牌酒店，房间有些味道，在可接受范围内。', '["https://dimg04.c-ctrip.com/images/0233x12000c3nmkblF289_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000c3mxj1j556F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000c3mw6hkE30B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-10', '红棉双床套房', '套房', '家庭亲子', 175, 0, 3, 9, '["餐饮设施","性价比","房间设施"]'::jsonb, '餐饮设施', '性价比', '房间设施'),
('68027e7de3c98b0941765c11', '酒店氛围很好，服务员工作主动热情 ，做事情忙而不乱。
酒店开业多年  但设施维护很好，并不显残旧，酒店所承载的历史反而成为酒店自身的魅力，这也是我选住花园酒店的主要原因。', '["https://dimg04.c-ctrip.com/images/0231r12000c4dzt4l995F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000c4e3x6rF3F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000c4e35rt8323_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000c4dzycs2A04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000c4e4bve9E33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000c4e4ac80F4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000c4e4a5v7F52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000c4dzyqe682F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '花园大床房', '大床房', '情侣出游', 85, 0, 6, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027e7de3c98b0941765c12', '房间舒适，设施完善。入住很是惬意，大堂很美，服务态度很好??', '["https://dimg04.c-ctrip.com/images/0236312000cqtpts96049_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000cqttqq9D916_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-16', '花园大床房', '大床房', '家庭亲子', 30, 0, 2, 5, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68027e7de3c98b0941765c13', '非常非常不建议这段时间入住，外面在施工太吵了，晚上施工到9，10点，听得无比烦躁，房间里压根不能待，早上7点就被施工的声音吵醒了，休假期间就想好好睡个觉，上一个酒店每天睡到9，10点才醒，这个酒店到好，7点就被吵醒，幸亏只订个一晚', '["https://dimg04.c-ctrip.com/images/0235o12000bzovub82ECF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000bzp0q5hEDC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000bzp0q5l3AE2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-08-24', '红棉大床套房', '套房', '独自旅行', 115, 2, 11, 8, '["安静程度","整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL),
('68027e7de3c98b0941765c14', '和父母来，本来是想再次回味一下广州的老牌酒店，没想到是这么的脏，打扫完的房间还有长头发，酒店茶餐厅的服务人员也非常排外，很明显提供不平等对待！', '["https://dimg04.c-ctrip.com/images/0234x12000cbx013o6647_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-10-05', '花园大床房', '大床房', '家庭亲子', 71, 0, 2, 7, '["卫生状况","前台服务"]'::jsonb, '卫生状况', '前台服务', NULL),
('68027e7de3c98b0941765c15', '房间非常不错，环境很漂亮噢！特别是酒店的大堂和用餐区，非常的气派，难怪有这么多外国友人过来！值得一提的是离地铁站非常非常的近，出行很方便。去广州塔，动物园，珠江夜游等景区五个站不到。晚上回来居然还有小点心。老人家出行必须要夸一下这里，配备了硬床板，腰疼得到了很好的缓解，以后来广州还会再来的，再次感谢花园酒店！', '["https://dimg04.c-ctrip.com/images/0231112000c34qqsk0B08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000c34m2c90DC9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000c34twdv5F4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000c34muyn565A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-07', '花园双床房', '双床房', '家庭亲子', 155, 0, 1, 9, '["交通便利性","房间设施","整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度'),
('68027e7de3c98b0941765c16', '设施：配套设施齐全
卫生：没异味
环境：很好，入住很舒服
服务：前台外国小哥哥很热情，赠送了鲜花，曲奇饼很好吃。服务很好，与价格匹配。', '["https://dimg04.c-ctrip.com/images/0233y12000cduta8wA5B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000cduxjko979E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000cdusicl6FA1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-13', '红棉大床套房', '套房', '商务出差', 67, 0, 3, 7, '["整体满意度","前台服务","性价比"]'::jsonb, '整体满意度', '前台服务', '性价比'),
('68027e7de3c98b0941765c17', '广州花园酒店，提前一天就接到电话问我有什么要求，升级房型，蜜月布置都满足了我的要求，因为是金卡还送了行政待遇，体验非常棒，以后有机会还来推荐给大家！', '["https://dimg04.c-ctrip.com/images/0232g12000caw9pyr1C4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000cawahxx8255_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000caw6wfi4F39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000cawg1va24D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000cawc9kh63A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000cawdeb8D22A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-01', '红棉大床套房', '套房', '情侣出游', 74, 0, 4, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027e7de3c98b0941765c18', '花园酒店名不虚传！精美的花园、齐全的设施、优质的服务（到店主动免费升级客房）。十分满意的入住体验，点赞！??????', '["https://dimg04.c-ctrip.com/images/0232d12000cbtsybe2B2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000cbtttxz6382_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000cbtstj404F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000cbtpxqt11AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000cbtpcii66DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000cbtr1cjA741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000cbtt6709A25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000cbtr1cn7777_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000cbtv6kb1373_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '红棉大床套房', '套房', '家庭亲子', 58, 0, 9, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027e7de3c98b0941765c19', '第三次入住了，重新装修后房间更加宽敞，床品高级舒适。品广州美食，领略岭南文化，非花园莫属??', '["https://dimg04.c-ctrip.com/images/0234b12000ckoc3ugEE2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000ckobcg63260_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000ckoeg6s196E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-15', '红棉大床套房', '套房', '家庭亲子', 46, 0, 2, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027e88e3c98b0941765c1a', '房间设施一般。
提前预订房间并扣费，楼层说了18-21层，且要求无烟房，备注好无异味。因私晚上11点多到店，被告知无要求的房间，临时换到低层，虽然是无烟房，也有异味。前厅服务态度一般。
晚上12点打客房服务，没人接听。早上8.9点打前台要求送矿泉水也等了40多分钟。', '["https://dimg04.c-ctrip.com/images/0234n12000byrfscn0623_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000byrcyzwD722_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000byrd4yd2013_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-21', '花园双床房', '双床房', '家庭亲子', 133, 1, 1, 7, '["房间设施","前台服务","客房服务"]'::jsonb, '房间设施', '前台服务', '客房服务'),
('68027e88e3c98b0941765c1b', '一家38年历史的老酒店，管理、服务依然是那么好。美中不足是设施上要更进一步才能赶上多元化多样性的需求，建议管理者从顾客多元化需求方面考虑改进。如枕头的软与硬。羽绒枕固然好，可我更喜欢乳胶枕，睡觉睡不好，整个人一天都不爽。住的时候刚好碰上泳池维修，没能畅游一番很是遗憾。', '["https://dimg04.c-ctrip.com/images/0236r12000bzam50aA064_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000bzam96b8F8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000bzaori1403C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-08-23', '花园大床房', '大床房', '家庭亲子', 134, 0, 4, 8, '["房间设施","公共设施","整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度'),
('68027e88e3c98b0941765c1c', '很愉快的一次入住！酒店环境好，服务棒！尤其是这次入住赠送行政酒廊的下午茶和欢乐时光，里面二个班的小姐姐都特别有趣有心！Katherine,Cherry,Yana这三个小姐妹我遇上了二次，尤其是Yana特别贴心，给我介绍酒店好玩好看的地方，谢谢啦！
Candy,Yuki,Lena这三个美女我遇上一次，也是很可爱的呢，给我推荐美食，及时给我调整不爱的食物，尤其是Yana的笑容，太治愈了！
我有用心记录了她们的名字，好的服务让我以后会继续选择这里的！
还有那些整理清洁的阿姨们，路上遇见也都是笑眯眯的和我们打招呼，太愉快了', '["https://dimg04.c-ctrip.com/images/0233712000c26wk2206CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000c270e9sB02D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000c26s7vuBC68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000c270cvdD461_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '花园双床房', '双床房', '家庭亲子', 260, 0, 2, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027e88e3c98b0941765c1d', '设施：先说床品，非常非常赞，保障了优质的睡眠。房间设施略老旧，出现短路跳闸的故障。

卫生：卫生不错。

环境：环境没得说，交通也方便。

服务：前台服务很专业，超预期。部分员工对于酒店位置设施不太熟悉，无法提供有用的指引。此次出行恰逢女伴生日，遗憾酒店未提供任何小惊喜。', '["https://dimg04.c-ctrip.com/images/0234g12000c0ugq4lA94D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000c0up8qi790C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000c0ugsjp108B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-28', '红棉大床套房', '套房', '情侣出游', 136, 1, 11, 7, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('68027e88e3c98b0941765c1e', '非常满意的一次体验。前台小哥哥服务态度很好，笑容也很好，告诉了我名字没记住。希望酒店可以表扬下。花园酒店整体还是不错的，房间也舒适，床很舒服。东西很好吃，喜欢粤菜。无论从性价比和舒适度都是非常不错的。下次还希望可以过来入住。', '["https://dimg04.c-ctrip.com/images/0231l2224wdp1g12p8E6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p2234ch27izy856AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d2215gabvdpchD3B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z2234ch27jn3kE028_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p2224wdp1h3nkB569_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z2215gabverxc134A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w2215gabvf7cw74D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-08', '红棉双床套房', '套房', '家庭亲子', 112, 0, 5, 7, '["整体满意度","前台服务","性价比"]'::jsonb, '整体满意度', '前台服务', '性价比')
 ON CONFLICT (_id) DO NOTHING;
